            "Condition B baseline not near zero at TR {}: {}", row, matrix[[row, 1]]);
    }

    // 4. UNDERSHOOT: HRF should show undershoot after peak
    let undershoot_idx = col_a_peak_idx + 10; // Look 10 TRs after peak
    if undershoot_idx < 100 {
        assert!(matrix[[undershoot_idx, 0]] < peak_val_a * 0.5,
            "No clear undershoot detected for condition A");
    }
}

#[test]
fn golden_test_baseline_model_polynomial_drift() {
    // golden-test-id: baseline_model_polynomial_drift

    // Create sampling frame: 120 time points, TR=2.0
    let sframe = create_test_sampling_frame(&[120], 2.0);

    // Create baseline model with polynomial drift, degree 2
    let baseline_spec = BaselineSpec::Polynomial { 
        degree: 2, 
        orthogonal: false, 
        intercept: true 
    };
    let baseline = BaselineModel::new(sframe.clone(), baseline_spec)
        .expect("Failed to create baseline model");

    let dm = baseline.design_matrix().expect("Failed to get design matrix");

    // Validate dimensions: 120 rows, 3 columns (constant, linear, quadratic)
    validate_dimensions(&dm, 120, 3);

    let matrix = dm.data();

    // 1. CONSTANT TERM: Should be all 1s
    check_column_sum(matrix, 0, 120.0, 0.001);
    for row in 0..120 {
        assert_abs_diff_eq!(matrix[[row, 0]], 1.0, epsilon = 0.001,
            "Constant term at row {} is not 1.0", row);
    }

    // 2. LINEAR TERM: Should be monotonically increasing
    for row in 1..120 {
        assert!(matrix[[row, 1]] > matrix[[row-1, 1]],
            "Linear term not monotonically increasing at row {}", row);
    }

    // 3. QUADRATIC TERM: Should show quadratic growth
    let start_val = matrix[[0, 2]];
    let mid_val = matrix[[60, 2]];
    let end_val = matrix[[119, 2]];

    // Quadratic should grow faster than linear
    assert!(end_val > mid_val * 1.5,
        "Quadratic term not showing expected growth pattern");

    // 4. RANGE: Polynomial terms should be properly scaled
    let linear_range = matrix.column(1).iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b)) -
                      matrix.column(1).iter().fold(f64::INFINITY, |a, &b| a.min(b));
    assert!(linear_range > 0.1, "Linear term range too small: {}", linear_range);
}

#[test]
fn golden_test_core_design_matrix_conditioning() {
    // golden-test-id: core_design_matrix_conditioning

    // Create a complex design matrix to test conditioning
    let sframe = create_test_sampling_frame(&[100], 2.0);

    // Create both baseline and event components
    let baseline_spec = BaselineSpec::Polynomial { 
        degree: 3, 
        orthogonal: true, 
        intercept: true 
    };
    let baseline = BaselineModel::new(sframe.clone(), baseline_spec)
        .expect("Failed to create baseline model");

    // Create events
    let mut events = Vec::new();
    for i in 0..10 {
        events.push((i as f64 * 10.0, "condition".to_string(), 1, 2.0));
    }

    let event_factor = EventFactor::from_events(&events, &sframe)
        .expect("Failed to create event factor");
    let event_model = EventModel::new(event_factor.into(), &sframe)
        .expect("Failed to create event model");

    // Combine baseline and events
    let mut builder = DesignMatrixBuilder::new(sframe.clone());
    builder.add_baseline(baseline).expect("Failed to add baseline");
    builder.add_event_model(event_model).expect("Failed to add event model");

    let dm = builder.build().expect("Failed to build design matrix");
    let matrix = dm.data();

    // 1. RANK: Matrix should be full rank (not singular)
    let condition_number = calculate_condition_number(matrix);
    assert!(condition_number < 1e12, 
        "Design matrix is poorly conditioned: condition number = {}", condition_number);

    // 2. NO PERFECT MULTICOLLINEARITY: No column should be a linear combination of others
    // This is implicitly tested by the condition number check

    // 3. REASONABLE SCALE: All columns should have reasonable variance
    for col in 0..matrix.ncols() {
        let col_data = matrix.column(col);
        let mean = col_data.mean().unwrap();
        let variance = col_data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / matrix.nrows() as f64;

        assert!(variance > 1e-10, "Column {} has near-zero variance: {}", col, variance);
        assert!(variance < 1e10, "Column {} has excessive variance: {}", col, variance);
    }
}

/// Helper function to calculate condition number (simplified approximation)
fn calculate_condition_number(matrix: &Array2<f64>) -> f64 {
    // For a proper condition number, we'd need SVD
    // This is a simplified approximation using column norms
    let mut min_norm = f64::INFINITY;
    let mut max_norm = 0.0;

    for col in 0..matrix.ncols() {
        let norm = matrix.column(col).iter().map(|&x| x * x).sum::<f64>().sqrt();
        min_norm = min_norm.min(norm);
        max_norm = max_norm.max(norm);
    }

    if min_norm > 0.0 {
        max_norm / min_norm
    } else {
        f64::INFINITY
    }
}

